chrome.runtime.onInstalled.addListener(()=>{chrome.contextMenus.create({id:"validateTextMenu",title:"Validate with AI Fact Checker",contexts:["selection"]})});chrome.contextMenus.onClicked.addListener((e,c)=>{e.menuItemId==="validateTextMenu"&&chrome.storage.local.set({selectedTextToValidate:e.selectionText},()=>{const t=chrome.runtime.getURL("index.html");chrome.windows.create({url:t,type:"popup",width:450,height:600})})});
